<script>
const SUPABASE_URL = 'https://hpyezixseggwnrpepbhx.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhweWV6aXhzZWdnd25ycGVwYmh4Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzY4MTUzMDgsImV4cCI6MjA5MjM5MTMwOH0.HGcrv7-I07yFES2qBRhXf1j3UCbfMb8PwlWkQjY6NYs';
const sbClient = supabase.createClient(SUPABASE_URL, SUPABASE_KEY);

var W1_CHUNK_COUNT = 28;
var W1_QUIZ_IDS = ['w1_q_vectors','w1_q_matrices','w1_q_lists','w1_q_dataframes'];

function getLang() {
  try { return localStorage.getItem('da_course_lang') || 'python'; } catch(e){ return 'python'; }
}

async function sbSaveProgress(key, value) {
  localStorage.setItem(key, value); 
  try {
    const { data: { user } } = await sbClient.auth.getUser();
    if (user) {
      await sbClient.from('progress').upsert({ 
        user_email: user.email,
        key: key,
        value: value
      });
    }
  } catch (err) { console.error("Supabase Save Error:", err); }
}

async function markChunkDone(chunkId) {
  const key = 'chunk_' + getLang() + '_' + chunkId;
  await sbSaveProgress(key, 'true');
  updateWeekBar();
}

async function markQuizDone(quizId) {
  const key = 'quiz_' + getLang() + '_w1_' + quizId;
  await sbSaveProgress(key, 'true');
  updateWeekBar();
}

async function updateWeekBar() {
  var lang = getLang();
  var total = W1_CHUNK_COUNT + W1_QUIZ_IDS.length;
  var done = 0;

  try {
    const { data: { user } } = await sbClient.auth.getUser();
    let progressMap = {};

    if (user) {
      const { data, error } = await sbClient
        .from('progress')
        .select('key, value')
        .eq('user_email', user.email);

      if (data) {
        data.forEach(row => { progressMap[row.key] = row.value === 'true'; });
      }
    }

    const isDone = (key) => {
      return progressMap[key] === true || localStorage.getItem(key) === 'true';
    };

    for (var i = 1; i <= W1_CHUNK_COUNT; i++) {
      if (isDone('chunk_' + lang + '_w1_c' + i)) done++;
    }
    W1_QUIZ_IDS.forEach(id => {
      if (isDone('quiz_' + lang + '_w1_' + id)) done++;
    });

    var pct = Math.round((done / total) * 100);
    var bar = document.getElementById('week1-progress-bar');
    var txt = document.getElementById('week1-progress-text');
    if (bar) { bar.style.width = pct + '%'; bar.innerText = pct > 8 ? pct + '%' : ''; }
    if (txt) { txt.innerText = done + ' of ' + total + ' tasks completed (' + lang.toUpperCase() + ')'; }
  } catch (err) { console.error("Update Bar Error:", err); }
}

// MutationObserver für Shinylive-Chunks
var _observedChunks = {};

function resetObservers() {
  _observedChunks = {};
  setTimeout(scanChunkWrappers, 300);
}

function observeChunkWrapper(wrapper) {
  var chunkId = wrapper.getAttribute('data-chunk-id');
  if (!chunkId || _observedChunks[chunkId]) return;
  _observedChunks[chunkId] = true;

  function tryAttach() {
    var iframe = wrapper.querySelector('iframe');
    if (!iframe) { setTimeout(tryAttach, 500); return; }
    function tryObserve() {
      try {
        var doc = iframe.contentDocument || iframe.contentWindow.document;
        if (!doc || !doc.body || doc.body.innerHTML.trim() === '') {
          setTimeout(tryObserve, 600); return;
        }
        var obs = new MutationObserver(function() {
          try {
            var pres = doc.querySelectorAll('pre');
            var hasOutput = false;
            pres.forEach(function(p) { if (p.innerText && p.innerText.trim()) hasOutput = true; });
            if (hasOutput) { obs.disconnect(); markChunkDone(chunkId); }
          } catch(e) {}
        });
        obs.observe(doc.body, { childList: true, subtree: true, characterData: true });
      } catch(e) { setTimeout(tryObserve, 800); }
    }
    tryObserve();
  }
  tryAttach();
}

function scanChunkWrappers() {
  document.querySelectorAll('.chunk-track[data-chunk-id]').forEach(observeChunkWrapper);
}

document.addEventListener('DOMContentLoaded', function() {
  updateWeekBar();
  setTimeout(scanChunkWrappers, 500);
  setTimeout(scanChunkWrappers, 2000);

  new MutationObserver(function(muts) {
    let found = false;
    muts.forEach(m => {
      m.addedNodes.forEach(n => {
        if (n.nodeType === 1 && (n.classList?.contains('chunk-track') || n.querySelector?.('.chunk-track'))) found = true;
      });
    });
    if (found) setTimeout(scanChunkWrappers, 300);
  }).observe(document.body, { childList: true, subtree: true });
});

window.addEventListener('message', function(e) {
  if (e.data && e.data.type === 'chunkDone' && e.data.chunkId) markChunkDone(e.data.chunkId);
});

// Language Switcher
document.addEventListener('DOMContentLoaded', function() {
  function applyFinalStyle() {
    var links = document.querySelectorAll('.navbar-nav .nav-link');
    var pyBtn, rBtn;
    links.forEach(function(l) {
      if (l.textContent.trim() === 'PYTHON') pyBtn = l;
      if (l.textContent.trim() === 'R') rBtn = l;
    });
    if (!pyBtn || !rBtn) { setTimeout(applyFinalStyle, 200); return; }
    var dg = '#1a4d1a';
    function updateView(lang) {
      document.querySelectorAll('.lang-python').forEach(function(el){ el.style.display = lang==='python'?'block':'none'; });
      document.querySelectorAll('.lang-r').forEach(function(el){ el.style.display = lang==='r'?'block':'none'; });
      pyBtn.style.cssText = 'background-color:'+(lang==='python'?dg:'white')+' !important;color:'+(lang==='python'?'white':dg)+' !important;border:2px solid '+dg+' !important;border-radius:50px !important;padding:5px 20px !important;margin:5px !important;font-weight:800 !important;';
      rBtn.style.cssText  = 'background-color:'+(lang==='r'?dg:'white')+' !important;color:'+(lang==='r'?'white':dg)+' !important;border:2px solid '+dg+' !important;border-radius:50px !important;padding:5px 20px !important;margin:5px !important;font-weight:800 !important;';
      try { localStorage.setItem('da_course_lang', lang); } catch(e){}
      updateWeekBar();
      resetObservers();
    }
    pyBtn.addEventListener('click', function(e){ e.preventDefault(); updateView('python'); });
    rBtn.addEventListener('click', function(e){ e.preventDefault(); updateView('r'); });
    var saved = localStorage.getItem('da_course_lang') || 'python';
    updateView(saved);
  }
  applyFinalStyle();
});
</script>


